package com.google.gson.internal;
import java.io.ObjectInputStream;
import java.io.ObjectStreamClass;
import java.lang.reflect.Field;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

class UnsafeAllocatorTest {

  @Test
  void assertInstantiable_whenCheckInstantiableReturnsNull_doesNotThrow() throws Exception {
    // Arrange
    Class<?> clazz = String.class;

    // Mock ConstructorConstructor to return null (instantiable)
    var constructorConstructorClass = Class.forName("com.google.gson.internal.ConstructorConstructor");
    var checkInstantiableMethod = constructorConstructorClass.getDeclaredMethod("checkInstantiable", Class.class);

    // Use reflection to get UnsafeAllocator.assertInstantiable
    Method assertInstantiable = UnsafeAllocator.class.getDeclaredMethod("assertInstantiable", Class.class);
    assertInstantiable.setAccessible(true);

    // Act & Assert: no exception thrown
    assertDoesNotThrow(() -> assertInstantiable.invoke(null, clazz));
  }

  @Test
  void assertInstantiable_whenCheckInstantiableReturnsMessage_throwsAssertionError() throws Exception {
    // Arrange
    Class<?> clazz = String.class;

    // Use reflection to get UnsafeAllocator.assertInstantiable
    Method assertInstantiable = UnsafeAllocator.class.getDeclaredMethod("assertInstantiable", Class.class);
    assertInstantiable.setAccessible(true);

    // Use Mockito spy to mock ConstructorConstructor.checkInstantiable to return non-null message
    // But ConstructorConstructor is not accessible here, so we simulate by creating a subclass that overrides method
    // Since method is static, we cannot mock easily without PowerMock, so we simulate by creating a dummy class

    // Instead, we use reflection to set the method accessible and replace it temporarily via instrumentation
    // This is complicated; so instead we test by passing a class that is known to be non-instantiable, e.g. an interface

    Class<?> nonInstantiableClass = Runnable.class;

    // Act & Assert: AssertionError is thrown with expected message
    AssertionError thrown = assertThrows(AssertionError.class, () -> assertInstantiable.invoke(null, nonInstantiableClass));

    String expectedMessageStart = "UnsafeAllocator is used for non-instantiable type: ";
    assertTrue(thrown.getMessage().startsWith(expectedMessageStart));
  }
}
